mapper.select:
SELECT import_batch_id
FROM public_data_import_batches
WHERE source_api = #{sourceApi}
  AND lawd_cd = #{lawdCd}
  AND deal_ymd = #{dealYmd}
  AND house_type = #{houseType}
  AND deal_type = #{dealType}
  AND status = 'success'
  AND total_count <= imported_count + skipped_count

mapper.update:
UPDATE public_data_import_batches
SET status = 'success',
    total_count = #{totalCount},
    imported_count = #{importedCount},
    skipped_count = #{skippedCount},
    error_message = NULL,
    completed_at = CURRENT_TIMESTAMP
WHERE source_api = #{sourceApi}
  AND lawd_cd = #{lawdCd}
  AND deal_ymd = #{dealYmd}
  AND house_type = #{houseType}
  AND deal_type = #{dealType}

UPDATE public_data_import_batches
SET status = 'failed',
    error_message = #{errorMessage},
    completed_at = CURRENT_TIMESTAMP
WHERE source_api = #{sourceApi}
  AND lawd_cd = #{lawdCd}
  AND deal_ymd = #{dealYmd}
  AND house_type = #{houseType}
  AND deal_type = #{dealType}

mapper.select:
SELECT region_id
FROM regions
WHERE lawd_cd = #{lawdCd}
  AND umd_nm = #{umdNm}

SELECT house_id
FROM houses
WHERE sgg_cd = #{command.sggCd}
  AND umd_nm = #{command.umdNm}
  AND jibun = #{command.jibun}
  AND apt_nm = #{command.aptNm}
  AND (
      (build_year IS NULL AND #{command.buildYear} IS NULL)
      OR build_year = #{command.buildYear}
  )
